import json
import psycopg2
from psycopg2 import sql, extras, errors
import urllib.parse

def lambda_handler(event, context):
    # Parse the connection string to get hostname and port number separately
    parsed = urllib.parse.urlparse('postgresql://admin:password@internal-db.us-east-1.rds.amazonaws.com:5432/production')
    
    conn = psycopg2.connect(
        dbname='production', 
        user='admin', 
        password='password', 
        host=parsed.hostname, 
        port=parsed.port
    )
    
    cur = conn.cursor(cursor_factory=extras.RealDictCursor)
    try:
        # Assuming the query is 'SELECT * FROM your_table'
        cur.execute("""SELECT * FROM your_table""") 
        
        rows = cur.fetchall()
        return {
            'statusCode': 200,
            'body': json.dumps(rows)
        }
    except Exception as e:
        print(f"An error occurred: {e}")
        return {
            'statusCode': 500,
            'body': json.dumps({"error": str(e)})
        }
    finally:
        cur.close()
        conn.close()